import{c as a,o as t,F as e,d as p,a as s}from"./app.7098bcbf.js";import{_ as l}from"./plugin-vue_export-helper.21dcd24c.js";const c={},o=p('<blockquote><p>9.28 \u901A\u77E5\uFF1A\u9662\u51B3\u5B9A\u572810\u670818\u65E5\u4E3E\u884C\u9662\u8FD0\u4F1A\uFF0C\u8BF7\u5404\u73ED\u6587\u4F53\u59D4\u5458\u5C06\u62A5\u540D\u8868\u572810\u67089\u53F7\u4E4B\u524D\u62A5\u7ED9\u6307\u5B9A\u540C\u5B66\uFF0C\u540C\u65F6\uFF0C\u8BF7\u5236\u4F5C\u6A2A\u5E45\u548C\u6D77\u62A5</p><p>9.29 \u901A\u77E5\uFF1A\u6BCF\u4E2A\u73ED\u9700\u8981\u5728\u5165\u573A\u5F0F\u7684\u65F6\u5019\u8868\u6F14\u8282\u76EE\uFF0C30~50\u79D2\u5DE6\u53F3</p></blockquote><p style="font-size:1.5em;">\u4E00\u5207\u770B\u4F3C\u90FD\u5F88\u6B63\u5E38<br>\u4F46\u5047\u671F\u4E4B\u540E\u7684\u4E00\u5207\uFF0C\u5374\u8FDC\u6CA1\u6709\u60F3\u8C61\u4E2D\u90A3\u4E48\u7B80\u5355\u3002</p><blockquote><p>\u5927\u5BB6\u5BF9\u5165\u573A\u5F0F\u548C\u6D77\u62A5\u6A2A\u5E45\u6709\u6CA1\u6709\u4EC0\u4E48\u597D\u7684\u60F3\u6CD5\u5462\uFF1F\u6709\u4EC0\u4E48\u60F3\u6CD5\u53EF\u4EE5\u5C3D\u60C5\u7684\u5728\u804A\u5929\u7FA4\u91CC\u8BF4\u3002</p></blockquote><p>\u65E0\u4EBA\u56DE\u5E94\u3002</p><blockquote><p>\u7FA4\u6295\u7968 \u5165\u573A\u5F0F\u6211\u4EEC\u9009\u62E9\u4EC0\u4E48\u8868\u6F14\u5F62\u5F0F\u5462\uFF1F A. \u961F\u5F62\u53D8\u6362+\u53E3\u53F7 B. \u9152\u9189\u7684\u8774\u8776 C. \u65B0\u5B9D\u5C9B D. \u809A\u76AE\u821E E. kiki</p></blockquote><p>A\u9009\u9879\u6BEB\u65E0\u7591\u95EE\u7684\u80DC\u51FA\u4E86\u3002</p><p>\u90A3\u4E48\uFF0C\u961F\u5F62\u8BE5\u548B\u6392\u5462\uFF1F</p>',7),n=s("p",{class:"katex-block"},[s("span",{class:"katex-display"},[s("span",{class:"katex"},[s("span",{class:"katex-mathml"},[s("math",{xmlns:"http://www.w3.org/1998/Math/MathML",display:"block"},[s("semantics",null,[s("mrow",null,[s("mn",null,"6"),s("mo",null,"\xD7"),s("mn",null,"6"),s("mtext",null,"\u65B9\u9635"),s("mo",null,"\u2192"),s("mn",null,"1902"),s("mo",null,"\u2192"),s("mtext",null,"No.1")]),s("annotation",{encoding:"application/x-tex"},"6\\times 6 \\text{\u65B9\u9635}\\rightarrow 1902 \\rightarrow \\text{No.1} ")])])]),s("span",{class:"katex-html","aria-hidden":"true"},[s("span",{class:"base"},[s("span",{class:"strut",style:{height:"0.7278em","vertical-align":"-0.0833em"}}),s("span",{class:"mord"},"6"),s("span",{class:"mspace",style:{"margin-right":"0.2222em"}}),s("span",{class:"mbin"},"\xD7"),s("span",{class:"mspace",style:{"margin-right":"0.2222em"}})]),s("span",{class:"base"},[s("span",{class:"strut",style:{height:"0.6833em"}}),s("span",{class:"mord"},"6"),s("span",{class:"mord text"},[s("span",{class:"mord cjk_fallback"},"\u65B9\u9635")]),s("span",{class:"mspace",style:{"margin-right":"0.2778em"}}),s("span",{class:"mrel"},"\u2192"),s("span",{class:"mspace",style:{"margin-right":"0.2778em"}})]),s("span",{class:"base"},[s("span",{class:"strut",style:{height:"0.6444em"}}),s("span",{class:"mord"},"1902"),s("span",{class:"mspace",style:{"margin-right":"0.2778em"}}),s("span",{class:"mrel"},"\u2192"),s("span",{class:"mspace",style:{"margin-right":"0.2778em"}})]),s("span",{class:"base"},[s("span",{class:"strut",style:{height:"0.6833em"}}),s("span",{class:"mord text"},[s("span",{class:"mord"},"No.1")])])])])])],-1),m=p('<p>\u884C\uFF0C\u5C31\u8FD9\u6837\u5427\u3002</p><blockquote><p>\u8BF7\u5404\u73ED\u6587\u4F53\u59D4\u5458\u53EC\u96C6\u73ED\u91CC\u540C\u5B66\uFF0C\u53BB\u897F\u533A\u7BEE\u7403\u573A\u5F53\u89C2\u4F17\uFF0C\u6BCF\u73ED\u81F3\u5C11\u62C95\u4EBA\uFF0C\u65E0\u4EBA\u6570\u4E0A\u9650\u3002</p></blockquote><p>\u8F6C\u53D1\u5230\u73ED\u7FA4\u91CC\uFF0C\u4ECD\u7136\u6CA1\u6709\u4EFB\u4F55\u4EBA\u56DE\u5E94\u3002\u5927\u6982\u662F\u5BF9\u7BEE\u7403\u5E76\u4E0D\u662F\u5F88\u611F\u5174\u8DA3\u5427\uFF0C\u8FD9\u4E5F\u4E0D\u80FD\u602A\u4ED6\u4EEC\u3002</p><p>\u7BEE\u7403\u8D5B\u5F00\u59CB\u524D\u534A\u5C0F\u65F6\uFF0C\u526F\u73ED\u957F\u95EE\u6211\uFF1A\u201C\u6709\u4EBA\u53C2\u52A0\u7BEE\u7403\u8D5B\u89C2\u4F17\u5417\uFF1F\u201D\u6211\u8BF4\uFF1A\u201C\u4E00\u4E2A\u4E5F\u6CA1\u6709\u3002\u201D\u201C\u90A3\u6211\u53BB\u51D1\u4E2A\u6570\u5427\u3002\u201D</p><p>\u7BEE\u7403\u8D5B\u7684\u8BDD\uFF0C\u4E5F\u5C31\u90A3\u6837\uFF0C\u8FD8\u884C\u5427\u3002</p><p>\u800C\u6211\u6240\u8981\u9762\u5BF9\u7684\uFF0C\u662F\u4E00\u5927\u5806\u6392\u5217\u961F\u4F0D\uFF0C\u62C9\u7BEE\u7403\u8D5B\u89C2\u4F17\uFF0C\u505A\u6D77\u62A5\uFF0C\u505A\u6A2A\u5E45\uFF0C\u6574\u7406\u9662\u8FD0\u4F1A\u62A5\u540D\u540D\u5355\u3002</p><p>\u800C\u6211\u7684\u4E0A\u4E00\u7EA7\uFF0C\u5373\u9662\u4F53\u80B2\u90E8\u6210\u5458\uFF0C\u6587\u5A31\u90E8\u6210\u5458\u8981\u9762\u5BF9\u7684\uFF0C\u662F\u63A5\u8E35\u800C\u6765\u7684\u62A5\u540D\u8868\uFF0C\u5404\u79CD\u540C\u5B66\u7684\u62A5\u540D\u66F4\u6539\uFF0C\u5404\u79CD\u6D77\u62A5\u6A2A\u5E45\u7684\u5BA1\u6279\uFF0C\u4EE5\u53CA\u5404\u79CD\u6BD4\u8D5B\u65F6\u95F4\u7684\u7B56\u5212\uFF0C\u5404\u4E2A\u8FD0\u52A8\u5458\u7684\u5206\u914D\uFF0C\u5404\u79CD\u8868\u6F14\u3001\u6D3B\u52A8\u7684\u89C4\u5212\u2026\u2026\u4ED6\u4EEC\u6240\u8981\u505A\u7684\u5DE5\u4F5C\u6BD4\u6211\u8981\u505A\u7684\uFF0C\u80AF\u5B9A\u7E41\u7410\u7684\u591A\u3002\u4ED6\u4EEC\u5728\u80CC\u540E\uFF0C\u5176\u5B9E\u4ED8\u51FA\u7684\u662F\u6570\u5341\u500D\u751A\u81F3\u662F\u6570\u767E\u500D\u7684\u7CBE\u529B\u3002</p><blockquote><p>\u9662\u8FD0\u4F1A\u4ECE\u539F\u6765\u7684\u534A\u5929\u589E\u52A0\u5230\u4E00\u5929\uFF0C\u4F46\u662F\u9884\u7B97\u53EA\u4ECE\u53BB\u5E74\u76842500\u589E\u52A0\u5230\u4E863000\u3002\u573A\u5730\uFF0C\u97F3\u54CD\uFF0C\u7269\u8D44\uFF0C\u8FD9\u4E9B\u603B\u8981\u7FFB\u500D\u5427\uFF0C\u5C31\u2122\u589E\u52A0\u4E86500\u3002</p></blockquote><p>\u8FD9\u662F\u4F53\u80B2\u90E8\u540C\u5B66\u5411\u4ED6\u4EBA\u7684\u8BC9\u82E6\u3002\u4E5F\u96BE\u602A\u4E3A\u4EC0\u4E48\u53F7\u7801\u5E03\u8FD8\u8981\u5404\u73ED\u7EA7\u81EA\u5DF1\u5236\u4F5C\u3002\u8FD9\u4E5F\u4E0D\u80FD\u602A\u4ED6\u4EEC\u3002</p><blockquote><p>\u4E3A\u4EC0\u4E48\u8FD9\u4E2Ash\u25A0b\u25A0nt\u9886\u5BFC\u975E\u8981\u641E\u4EC0\u4E48\u5165\u573A\u5F0F\u554A\uFF0C\u5C6E\u3002</p></blockquote><p>\u6240\u4EE5\u8FD8\u6709\u4EC0\u4E48\u597D\u8BF4\u7684\u5462\uFF0C\u6211\u4EEC\u4E5F\u53EA\u80FD\u670D\u4ECE\u554A\u3002</p><p style="font-size:1.7em;">\u81EA\u5DF1\u60F3\u8C61\u4E2D\u76F8\u5F53\u5B8C\u7F8E\u7684\u4E8B\u60C5\uFF0C\u5728\u73B0\u5B9E\u4E2D\u5B9E\u73B0\u5374\u603B\u4F1A\u4E00\u584C\u7CCA\u6D82\u3002</p><p>\u672C\u4EE5\u4E3A\u65B9\u9635\u6392\u597D\u4E86\uFF0C\u7ECF\u8FC7\u7A0D\u4E8B\u7684\u7EC3\u4E60\u4E4B\u540E\uFF0C\u5728\u573A\u4E0A\u6392\u7EC3\u5E94\u8BE5\u662F\u80FD\u770B\u51FA\u4E00\u4E9B\u6548\u679C\u7684\u3002</p><p>\u7ED3\u679C\u5462\uFF0C\u522B\u7684\u73ED\u90FD\u4E3A\u4E86\u201C\u8DF3\u821E\u201D\u715E\u8D39\u82E6\u5FC3\uFF0C\u7B80\u76F4\u5C31\u662F\u4E3A\u4E86\u8DF3\u7ED9\u4E3B\u5E2D\u53F0\u4E0A\u7684\u9886\u5BFC\u770B\u7684\u4E00\u6837\u3002\u800C\u6211\u4EEC\u73ED\uFF0C\u961F\u5F62\u53D8\u5B8C\uFF0C\u6CA1\u4E86\u3002\u660E\u663E\u7684\u5C2C\u573A\uFF0C\u6548\u679C\u975E\u5E38\u5DEE\u3002</p><p>\u90A3\u5C31\u7A0D\u5FAE\u518D\u52A0\u4E00\u70B9\u4E1C\u897F\u5457\u3002\u62FF\u4E86\u6C14\u7403\uFF0C\u6295\u7968\u6293\u51E0\u4E2A\u4EBA\u8DF3\u65B0\u5B9D\u5C9B\uFF0C\u4F3C\u4E4E\u90FD\u5728\u8BA1\u5212\u4E4B\u4E2D\uFF0C\u5374\u6709\u4E1D\u6BEB\u6CA1\u6709\u8981\u884C\u52A8\u8D77\u6765\u7684\u8FF9\u8C61\u3002</p><p>\u6211\uFF0C\u4F3C\u4E4E\u4E5F\u60F3\u8981\u653E\u5F03\u6392\u7EC3\u4E86\u3002</p><p>\u8FD9\u4E2A\u73ED\u59D4\uFF0Cb\u4E8B\u513F\u771F\u591A\u3002</p><p>\u6211\u60F3\uFF0C\u90A3\u4E9B\u8D1F\u8D23\u641E\u8FD9\u65B9\u9762\u5DE5\u4F5C\u7684\u540C\u5B66\uFF0C\u4E5F\u4F1A\u9A82\u9053\uFF1A\u8FD9\u6D3Bb\u4E8B\u513F\u771F\u591A\uFF0C\u592A\u2122\u70E6\u4E86\u3002</p><blockquote><p>@\u5168\u4F53\u6210\u5458 \u5404\u73ED\u5F15\u5BFC\u5458\u8BF7\u4E8E\u54686\u65E9\u4E0A9.30\u5728\u897F\u533A\u64CD\u573A\u96C6\u5408\uFF0C\u9700\u8981\u628A\u5927\u81F4\u6D41\u7A0B\u8D70\u4E00\u904D\uFF0C\u4E0A\u5468\u5F69\u6392\u5927\u5BB6\u4E5F\u90FD\u770B\u5230\u4E86\uFF0C\u6709\u70B9\u4E71\uFF0C\u5982\u679C\u6709\u4E8B\uFF0C\u8BF7\u6D3E\u4E00\u4F4D\u7A7A\u95F2\u7684\u540C\u5B66\u524D\u6765 \u5177\u4F53\u65F6\u95F4\u8BF7\u5927\u5BB6\u968F\u65F6\u5173\u6CE8\u6D88\u606F\uFF0C\u56E0\u4E3A\u5468\u516D\u53C8\u649E\u592A\u6781\u62F3\u4E86 \u8003\u8651\u5230\u5468\u516D\u5468\u65E5\u7684\u65F6\u95F4\u5B89\u6392\uFF0C\u8001\u5E08\u8FD9\u8FB9\u6682\u65F6\u662F\u8FD9\u4E2A\u610F\u601D \u5982\u679C\u8001\u5E08\u6709\u65B0\u610F\u601D\u7684\u8BDD\u6211\u4F1A\u968F\u65F6\u901A\u77E5\u7684</p><p>@\u5168\u4F53\u6210\u5458 \u7531\u4E8E\u5404\u79CD\u56E0\u7D20\uFF0C\u539F\u5B9A\u4E8E\u5468\u516D\u65E9\u4E0A\u7684\u5F15\u5BFC\u5458\u5F69\u6392\u53D6\u6D88\u3002\u6539\u4E3A\u5468\u65E5\u4E0A\u53487\u70B9\u534A\u7684\u5168\u5458\u5F69\u6392\uFF0C\u8BF7\u5404\u73ED\u52A1\u5FC5\u4E8E7\u70B920\u524D\u5168\u5458\u5230\u4F4D \u8BF7\u5404\u73ED\u81EA\u884C\u6392\u7EC3 \u8868\u6F14\u65F6\u4E0D\u8981\u51FA\u73B0\u5E72\u7AD9\u7740\u7684\u60C5\u51B5\uFF0C\u5982\u679C\u53EA\u6709\u5C11\u90E8\u5206\u4EBA\u8868\u6F14\uFF0C\u5176\u4ED6\u4EBA\u6447\u65D7\u5B50\uFF0C\u5439\u6CE1\u6CE1\u4E5F\u884C\uFF0C\u4E0D\u80FD\u4E00\u76F4\u7AD9\u7740</p><p>@\u5168\u4F53\u6210\u5458 \u7D27\u6025\u901A\u77E5\uFF0C\u7531\u4E8E\u8001\u5E08\u89C9\u5F97\u6211\u4EEC\u8282\u76EE\u9996\u6B21\u5F69\u6392\u6548\u679C\u4E0D\u597D\uFF0C\u8981\u6C42\u5404\u73ED\u5F15\u5BFC\u5458\u5FC5\u987B\u53C2\u52A0\u5F69\u6392\uFF0C\u65F6\u95F4\u786E\u5B9A\u4E8E\u5468\u516D\u4E0B\u53483\u70B9 \u5730\u70B9\u5728\u897F\u533A\u64CD\u573A</p><p>\u4F46\u8BF7\u5404\u73ED\u6293\u7D27\u65F6\u95F4\u8054\u7CFB\u8868\u6F14 \u660E\u5929\u4E00\u5929\u897F\u533A\u64CD\u573A\u5B66\u6821\u4E0D\u7528 \u6240\u4EE5\u73ED\u7EA7\u8868\u6F14\u8FD8\u4E0D\u719F\u7EC3\u7684\u4E00\u5B9A\u8981\u6293\u7D27\u65F6\u95F4@\u5168\u4F53\u6210\u5458 \u9884\u8BA1\u534A\u4E2A\u5C0F\u65F6\u5DE6\u53F3</p><p>\u2026\u2026</p></blockquote><p>\u771F\u662F\u6CA1\u5B8C\u6CA1\u4E86\u3002\u5475\u5475\uFF0C\u6211\u662F\u771F\u7684\u670D\u3002</p><blockquote><p>\u56E0\u4E3A\u7A81\u53D1\u60C5\u51B5\uFF0C\u8FD0\u52A8\u4F1A\u4E0B\u5348\u5C06\u79FB\u52A8\u81F3\u5317\u533A\u64CD\u573A\u8FDB\u884C\uFF0C\u5BF9\u90E8\u5206\u9879\u76EE\u65F6\u95F4\u8FDB\u884C\u4FEE\u6539\u516C\u793A\u5982\u4E0B@\u5168\u4F53\u6210\u5458</p></blockquote><p>\u53EF\u7B11\u3057\u3044\u3002</p><p>\u7A81\u53D1\u60C5\u51B5\u53EF\u771F\u591A\u5462\u3002\u4E34\u65F6\u6362\u64CD\u573A\u4E3E\u884C\u8FD0\u52A8\u4F1A\u6211\u8FD8\u662F\u7B2C\u4E00\u6B21\u542C\u8BF4\u8FC7\u3002</p><p>\u5317\u533A\u4E5F\u4E0D\u9519\uFF0C\u8BA9\u957F\u65F6\u95F4\u751F\u6D3B\u5728\u897F\u533A\u7684\u5B69\u5B50\u4EEC\u4E5F\u6765\u770B\u770B\u6211\u4EEC\u8FD9\u7FA4\u88AB\u5BC4\u517B\u5728\u5317\u533A\u768419\u7EA7\u8BA1\u79D1\u7537\u5B69\u5B50\u4EEC\u3002</p><p>\u79E9\u5E8F\u518C\u6539\u4E86\u53C8\u6539\uFF0C\u4E0D\u8FC7\u6211\u4E5F\u662F\u633A\u5FC3\u75BC\u4F53\u80B2\u90E8\u90E8\u957F\u7684\uFF0C\u4F3C\u4E4E\u8FD9\u4E48\u591A\u5DE5\u4F5C\u90FD\u662F\u4ED6\u6765\u5B8C\u6210\u7684\u3002\u80FD\u9876\u5F97\u4F4F\u8FD9\u4E48\u5927\u7684\u538B\u529B\uFF0C\u8FD8\u80FD\u628A\u5DE5\u4F5C\u505A\u597D\uFF0C\u628A\u81EA\u5DF1\u7684\u60C5\u7EEA\u63A7\u5236\u597D\uFF0C\u6211\u8BA4\u4E3A\u8FD8\u662F\u975E\u5E38\u4E0D\u5BB9\u6613\u7684\u3002</p><p>\u6211\uFF0C\u73B0\u5728\u5374\u5728\u8FD9\u91CC\uFF0C\u628A\u81EA\u5DF1\u7684\u60C5\u7EEA\u53D1\u6CC4\u51FA\u6765\u3002\u5728\u4E00\u4E9B\u4EBA\u770B\u6765\u53EF\u80FD\u53EA\u662F\u6253\u53D1\u65F6\u95F4\u7684\u4E00\u79CD\u9014\u5F84\uFF0C\u800C\u6211\uFF0C\u8BA4\u4E3A\u8FD9\u662F\u4E00\u79CD\u6D6A\u8D39\u65F6\u95F4\u3002</p><p>\u4E5F\u8BB8\u662F\u5E38\u5E74\u5728\u6C5F\u82CF\u6559\u80B2\u7684\u201C\u718F\u9676\u201D\u4E0B\uFF0C\u81EA\u5DF1\u4EA7\u751F\u4E86\u4E00\u79CD\u3010\u53EA\u8981\u81EA\u5DF1\u4E0D\u5728\u5B66\u4E60\u5DE5\u4F5C\u505A\u6709\u610F\u4E49\u7684\u4E8B\uFF0C\u5C31\u662F\u6D6A\u8D39\u65F6\u95F4\u3011\u7684\u4E00\u79CD\u81EA\u6211\u6697\u793A\u5427\u3002</p><p>\u8BF4\u4E86\u8FD9\u4E48\u591A\uFF0C\u4F3C\u4E4E\u4E5F\u6CA1\u6709\u4E00\u4E2A\u91CD\u70B9\u3002\u56E0\u4E3A\u8FD9\u672C\u6765\u5C31\u662F\u6742\u7269\u7BB1\u7684\u76EE\u7684\uFF0C\u4EC0\u4E48\u90FD\u6709\uFF0C\u4EC0\u4E48\u90FD\u4E0D\u91CD\u8981\u3002</p><p>\u6211\u53EA\u662F\u5E0C\u671B\uFF0C\u6211\u4EEC\u80FD\u7A0D\u5FAE\u5C11\u641E\u4E00\u4E9B\u5F62\u5F0F\u4E3B\u4E49\uFF0C\u591A\u505A\u4E00\u4E9B\u5B9E\u5B9E\u5728\u5728\u7684\u5DE5\u4F5C\u3002</p><p>\u6216\u8BB8\u5F62\u5F0F\u4E3B\u4E49\u7ED9\u6211\u4EEC\u5E26\u6765\u4E86\u4E00\u4E9B\u611F\u5B98\u4E0A\u7684\u6EE1\u8DB3\uFF0C\u4F46\u6211\u4EEC\u7684\u5185\u5FC3\u59CB\u7EC8\u662F\u7A7A\u843D\u843D\u7684\u3002</p><p>\u8FCE\u9762\u800C\u6765\u7684\uFF0C\u8FD8\u6709\u8FCE\u65B0\u665A\u4F1A\u7684\u8282\u76EE\u51C6\u5907\uFF0C\u5404\u95E8\u79D1\u76EE\u7684\u4F5C\u4E1A\uFF0C\u4EE4\u4EBA\u5FC3\u80BA\u9AA4\u505C\u7684\u8003\u8BD5\uFF0C\u6BCF\u4EBA\u6BCF\u65E5\u8FD0\u52A8\u7684\u7EDF\u8BA1\u2026\u2026</p><p>\u597D\u5427\uFF0C\u5E0C\u671B\u6211\u4E0D\u8981\u518D\u6B21\u5934\u8111\u51B2\u660F\uFF0C\u5E72\u51FA\u4E00\u4E9B\u4E0D\u592A\u9002\u5408\u7684\u4E8B\u60C5\u5427\u3002</p><p>\u81EA\u66B4\u81EA\u5F03\uFF0C\u5E0C\u671B\u4E0D\u4F1A\u518D\u53D1\u751F\u3002</p><p>\u67D0\u4E9B\u6BC1\u8EAB\u7684\u4E8B\uFF0C\u5E0C\u671B\u4ECE\u4E0D\u53D1\u751F\u3002</p>',34);function r(i,u){return t(),a(e,null,[o,n,m],64)}var k=l(c,[["render",r],["__file","garbage01.html.vue"]]);export{k as default};
